
package com.example.taxgap.service; import com.example.taxgap.domain.dto.*; import com.example.taxgap.domain.entity.FinancialTransaction; import com.example.taxgap.domain.enums.*; import com.example.taxgap.repository.FinancialTransactionRepository; import com.fasterxml.jackson.databind.ObjectMapper; import jakarta.transaction.Transactional; import jakarta.validation.Valid; import org.springframework.stereotype.Service; import java.time.LocalDate; import java.util.*; import java.math.BigDecimal;
@Service public class TransactionService { private final FinancialTransactionRepository repo; private final AuditLogService audit; private final TaxComputationService tax; private final RuleEngineService rules; private final ObjectMapper mapper; public TransactionService(FinancialTransactionRepository r, AuditLogService a, TaxComputationService t, RuleEngineService re, ObjectMapper m){repo=r;audit=a;tax=t;rules=re;mapper=m;} @Transactional public TransactionUploadResponse upload(@Valid TransactionUploadRequest req){ int success=0, failed=0; List<String> failedIds=new ArrayList<>(); for(TransactionUploadItem item: req.getTransactions()){ FinancialTransaction ft=new FinancialTransaction(); ft.setTransactionId(item.getTransactionId()); ft.setCustomerId(item.getCustomerId()); ft.setTransactionType(item.getTransactionType()); ft.setReportedTax(item.getReportedTax()); ft.setOriginalSaleTransactionId(item.getOriginalSaleTransactionId()); List<String> failures=new ArrayList<>(); try{ ft.setDate(LocalDate.parse(item.getDate())); }catch(Exception ex){ failures.add("Invalid date format. Expected yyyy-MM-dd."); } if(item.getAmount()==null || item.getAmount().compareTo(new BigDecimal("0.00"))<=0) failures.add("Amount must be > 0"); else ft.setAmount(item.getAmount()); if(item.getTaxRate()==null) failures.add("taxRate required"); else ft.setTaxRate(item.getTaxRate()); if(item.getTransactionId()==null || item.getTransactionId().isBlank()) failures.add("transactionId required"); if(item.getCustomerId()==null || item.getCustomerId().isBlank()) failures.add("customerId required"); if(item.getTransactionType()==null) failures.add("transactionType required"); if(!failures.isEmpty()){ ft.setValidationStatus(ValidationStatus.FAILURE); ft.setFailureReasonsJson(toJson(Map.of("reasons", failures))); repo.save(ft); audit.log(EventType.INGESTION, ft.getTransactionId(), Map.of("status","FAILURE","reasons",failures)); failed++; failedIds.add(ft.getTransactionId()); continue; } ft.setValidationStatus(ValidationStatus.SUCCESS); repo.save(ft); audit.log(EventType.INGESTION, ft.getTransactionId(), Map.of("status","SUCCESS")); tax.compute(ft); repo.save(ft); rules.executeAll(ft); success++; } return new TransactionUploadResponse(req.getTransactions().size(), success, failed, failedIds); } private String toJson(Object o){ try{ return mapper.writeValueAsString(o);}catch(Exception e){return "{}";} } }
